"use client";
import { useState } from "react";
import { AlertTriangle, Shield, Lock, Navigation, Zap, Map, CheckCircle, XCircle, HelpCircle, Cpu, ChevronRight, ChevronDown, Eye } from "lucide-react";

const EVENT_TYPE_CONFIG = {
  fence_alert: { icon: Shield, color: "#f59e0b", label: "Fence Alert" },
  vehicle_movement: { icon: AlertTriangle, color: "#ef4444", label: "Vehicle" },
  badge_failure: { icon: Lock, color: "#ef4444", label: "Badge Fail" },
  drone_patrol: { icon: Navigation, color: "#3b82f6", label: "Drone" },
  signal_anomaly: { icon: Zap, color: "#8b5cf6", label: "Anomaly" },
};

const VERDICT_CONFIG = {
  escalate: { label: "ESCALATE", color: "#ef4444", bg: "rgba(239,68,68,0.12)", border: "rgba(239,68,68,0.3)" },
  likely_harmless: { label: "LIKELY HARMLESS", color: "#6ee7b7", bg: "rgba(16,185,129,0.08)", border: "rgba(16,185,129,0.25)" },
  routine: { label: "ROUTINE", color: "#c4b5fd", bg: "rgba(139,92,246,0.1)", border: "rgba(139,92,246,0.25)" },
};

export default function EventTimeline({ events, selectedEvent, onSelectEvent, onVerdict, onFocusMap, agentDone }) {
  const [filter, setFilter] = useState("all");

  const filtered = filter === "all" ? events : events.filter(e => e.type === filter || (filter === "escalate" && e.aiAssessment?.verdict === "escalate"));

  return (
    <div className="section-card">
      <div className="flex items-center justify-between mb-4">
        <div>
          <h2 className="text-sm font-semibold" style={{ color: "var(--text-primary)" }}>Overnight Events</h2>
          <div className="text-xs mt-0.5" style={{ color: "var(--text-muted)" }}>22:00 – 06:10 · {events.length} total events</div>
        </div>
        {agentDone && (
          <div className="text-xs px-2 py-1 rounded"
            style={{ background: "rgba(239,68,68,0.1)", color: "#fca5a5", border: "1px solid rgba(239,68,68,0.25)" }}>
            {events.filter(e => e.aiAssessment?.verdict === "escalate").length} to escalate
          </div>
        )}
      </div>

      {/* Filter bar */}
      <div className="flex gap-2 mb-4 flex-wrap">
        {[
          { id: "all", label: "All" },
          { id: "escalate", label: "Escalate", hidden: !agentDone },
          { id: "fence_alert", label: "Fence" },
          { id: "vehicle_movement", label: "Vehicle" },
          { id: "badge_failure", label: "Badge" },
          { id: "drone_patrol", label: "Drone" },
          { id: "signal_anomaly", label: "Signals" },
        ].filter(f => !f.hidden).map(f => (
          <button key={f.id} onClick={() => setFilter(f.id)}
            className="px-2.5 py-1 rounded-lg text-xs font-medium transition-all"
            style={{
              background: filter === f.id ? "rgba(245,158,11,0.15)" : "var(--surface-2)",
              border: `1px solid ${filter === f.id ? "rgba(245,158,11,0.35)" : "var(--border-subtle)"}`,
              color: filter === f.id ? "var(--brand-amber)" : "var(--text-muted)",
            }}>
            {f.label}
          </button>
        ))}
      </div>

      {/* Timeline */}
      <div className="space-y-2">
        {filtered.map(event => (
          <EventRow
            key={event.id}
            event={event}
            selected={selectedEvent === event.id}
            onSelect={() => onSelectEvent(event.id)}
            onVerdict={onVerdict}
            onFocusMap={onFocusMap}
            agentDone={agentDone}
          />
        ))}
      </div>
    </div>
  );
}

function EventRow({ event, selected, onSelect, onVerdict, onFocusMap, agentDone }) {
  const config = EVENT_TYPE_CONFIG[event.type];
  const Icon = config.icon;
  const verdict = event.aiAssessment ? VERDICT_CONFIG[event.aiAssessment.verdict] : null;

  return (
    <div
      onClick={onSelect}
      className="rounded-lg overflow-hidden cursor-pointer transition-all duration-200"
      style={{
        background: selected ? "var(--surface-2)" : "var(--surface-0)",
        border: `1px solid ${selected ? "rgba(245,158,11,0.25)" : "var(--border-subtle)"}`,
      }}
    >
      <div className="flex items-center gap-3 px-3 py-3">
        {/* Time bar indicator */}
        <div className="flex flex-col items-center shrink-0">
          <div className="w-px h-2 opacity-20" style={{ background: config.color }} />
          <div className="w-7 h-7 rounded-lg flex items-center justify-center"
            style={{ background: `${config.color}15`, border: `1px solid ${config.color}30` }}>
            <Icon size={13} style={{ color: config.color }} />
          </div>
          <div className="w-px flex-1 opacity-20 mt-1" style={{ background: config.color, minHeight: 8 }} />
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span className="text-xs font-mono font-medium" style={{ color: "var(--text-muted)" }}>{event.time}</span>
            <span className={`badge-${event.severity} text-xs px-1.5 py-0.5 rounded font-semibold`}>
              {event.severity.toUpperCase()}
            </span>
            {verdict && agentDone && (
              <span className="text-xs px-2 py-0.5 rounded font-medium"
                style={{ background: verdict.bg, color: verdict.color, border: `1px solid ${verdict.border}` }}>
                {verdict.label}
              </span>
            )}
          </div>
          <div className="text-sm font-medium mt-0.5" style={{ color: "var(--text-primary)" }}>{event.title}</div>
          <div className="text-xs mt-0.5 truncate" style={{ color: "var(--text-muted)" }}>{event.location}</div>
        </div>

        {/* Right side */}
        <div className="flex items-center gap-1.5 shrink-0">
          {event.userVerdict === "approved" && <CheckCircle size={14} style={{ color: "#6ee7b7" }} />}
          {event.userVerdict === "challenged" && <XCircle size={14} style={{ color: "#fca5a5" }} />}
          {agentDone && !event.userVerdict && (
            <div className="w-2 h-2 rounded-full animate-pulse" style={{ background: "var(--brand-amber)" }} />
          )}
          <button
            onClick={e => { e.stopPropagation(); onFocusMap(event); }}
            className="p-1 rounded transition-colors hover:bg-gray-800"
            style={{ color: "var(--text-muted)" }}>
            <Map size={12} />
          </button>
          <ChevronRight size={14} style={{ color: "var(--text-muted)", transform: selected ? "rotate(90deg)" : "none", transition: "transform 0.2s" }} />
        </div>
      </div>

      {/* Expanded detail */}
      {selected && (
        <div className="px-3 pb-3 border-t" style={{ borderColor: "var(--border-subtle)" }}>
          <p className="text-xs mt-2 leading-relaxed" style={{ color: "var(--text-secondary)" }}>{event.description}</p>

          {/* Raw data */}
          <div className="mt-2 grid grid-cols-2 gap-1">
            {Object.entries(event.rawData).slice(0, 4).map(([k, v]) => (
              <div key={k} className="text-xs">
                <span style={{ color: "var(--text-muted)" }}>{k}: </span>
                <span style={{ color: "var(--text-secondary)" }}>{String(v)}</span>
              </div>
            ))}
          </div>

          {/* Tags */}
          <div className="flex gap-1 mt-2 flex-wrap">
            {event.tags.map(tag => (
              <span key={tag} className="text-xs px-1.5 py-0.5 rounded"
                style={{ background: "var(--surface-3)", color: "var(--text-muted)" }}>
                #{tag}
              </span>
            ))}
          </div>

          {/* Confidence indicator if AI done */}
          {event.aiAssessment && (
            <div className="mt-3 flex items-center gap-2">
              <Cpu size={11} style={{ color: "var(--brand-amber)" }} />
              <span className="text-xs" style={{ color: "var(--text-muted)" }}>AI Confidence:</span>
              <div className="flex-1 h-1 rounded-full" style={{ background: "var(--surface-3)" }}>
                <div className="h-full rounded-full"
                  style={{
                    width: `${event.aiAssessment.confidence * 100}%`,
                    background: verdict?.color || "var(--brand-amber)",
                  }} />
              </div>
              <span className="text-xs font-mono" style={{ color: verdict?.color || "var(--brand-amber)" }}>
                {Math.round(event.aiAssessment.confidence * 100)}%
              </span>
            </div>
          )}

          {/* Human review */}
          <div className="flex gap-2 mt-3">
            <button onClick={(e) => { e.stopPropagation(); onVerdict(event.id, "approved"); }}
              className="flex-1 py-1.5 rounded text-xs font-medium transition-all"
              style={{
                background: event.userVerdict === "approved" ? "rgba(16,185,129,0.15)" : "var(--surface-2)",
                border: `1px solid ${event.userVerdict === "approved" ? "rgba(16,185,129,0.3)" : "var(--border-subtle)"}`,
                color: event.userVerdict === "approved" ? "#6ee7b7" : "var(--text-muted)",
              }}>
              ✓ Approve
            </button>
            <button onClick={(e) => { e.stopPropagation(); onVerdict(event.id, "challenged"); }}
              className="flex-1 py-1.5 rounded text-xs font-medium transition-all"
              style={{
                background: event.userVerdict === "challenged" ? "rgba(239,68,68,0.12)" : "var(--surface-2)",
                border: `1px solid ${event.userVerdict === "challenged" ? "rgba(239,68,68,0.3)" : "var(--border-subtle)"}`,
                color: event.userVerdict === "challenged" ? "#fca5a5" : "var(--text-muted)",
              }}>
              ✕ Challenge
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
